1	// claim-office.ts
2	
3	type Item = { type: string };
4	
5	type Step = { op: string; items: Item[] };
6	
7	type Scenario = {
8	  customer: { yearsWithMHPCO: number };
9	  steps: Step[];
10	};
11	
12	type StepResult = { premium: number };
13	
14	type ScenarioResult = {
15	  results: StepResult[];
16	};
17	
18	const BASE_PREMIUMS: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
28	const PROCESSING_FEE = 5;
29	
30	const RUNE_BLOCK_SIZE = 3;
31	const RUNE_BLOCK_BASE_PREMIUM = 60;
32	
33	const isRuneBlock = (items: Item[]): boolean =>
34	  items.length === RUNE_BLOCK_SIZE &&
35	  items.every((item) => item.type === "rune");
36	
37	const calculateTotalBasePremium = (items: Item[]): number =>
38	  isRuneBlock(items)
39	    ? RUNE_BLOCK_BASE_PREMIUM
40	    : items.reduce((total, item) => total + BASE_PREMIUMS[item.type], 0);
41	
42	const quoteStep = (step: Step): StepResult => {
43	  const totalBasePremium = calculateTotalBasePremium(step.items);
44	  const firstInsuranceSurcharge =
45	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
46	  return {
47	    premium: Math.ceil(
48	      totalBasePremium + firstInsuranceSurcharge + PROCESSING_FEE,
49	    ),
50	  };
51	};
52	
53	export const processScenario = (scenario: Scenario): ScenarioResult => ({
54	  results: scenario.steps.map(quoteStep),
55	});
